		}
		b := 0
		if i+1 < n {
			b = right[i+1]
		}
		if i > 0 && i+1 < n && nums[i-1] > nums[i+1] {
			ans = max(ans, max(a+1, b+1))
		} else {
			ans = max(ans, a+b+1)
		}
	}

	return ans
}

